mapper.select:
select a.sfid, a.phonenumber, a.jtxcompanyid, a.dispatchtype as dispatchtype,
a.appdisplayname, a.salesprefecture, CASE
    WHEN w.sycapproveflg = 'T' THEN 0
    ELSE 1
END 
AS isneedapproval
FROM appcompany a
INNER JOIN worker w on a.sfid = w.sfid
 where a.jtxcompanyid < #{jtxCompanyId} 
 where w.sycapproveflg != #{flg} 
 where a.jtxcompanyid < #{jtxCompanyId} AND w.sycapproveflg != #{flg} 
ORDER BY a.jtxCompanyId DESC
 LIMIT ${limit}
